module top_module(cmp_A, B, EQ, GT, LT);input [3:0] cmp_A, B;
output EQ, GT, LT;

reg EQ, GT, LT;

always @(*) begin
    if (cmp_A == B) begin
        EQ = 1;
        GT = 0;
        LT = 0;
    end
    else if (cmp_A > B) begin
        EQ = 0;
        GT = 1;
        LT = 0;
    end
    else begin
        EQ = 0;
        GT = 0;
        LT = 1;
    end
end

endmodule
